import{_ as a,o,c as t,ag as s}from"./chunks/framework.BPmc_f4o.js";const u=JSON.parse('{"title":"Deployment","description":"","frontmatter":{},"headers":[],"relativePath":"deployment.md","filePath":"deployment.md"}'),i={name:"deployment.md"};function n(l,e,r,d,p,c){return o(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="deployment" tabindex="-1">Deployment <a class="header-anchor" href="#deployment" aria-label="Permalink to &quot;Deployment&quot;">​</a></h1><p>Brut apps are Rack apps, so they can be deployed in conventional ways.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>There are just too many ways to deploy. Brut attempts to address this by adhering to <a href="https://12factor.net" target="_blank" rel="noreferrer">12-factor principles</a>. You can get your app to production and run <code>bin/run</code> and it should work.</p><p>That said, Brut currently provides explicit support for two methods of deployment: Heroku (using containers) and a generalized Docker Image mechanism.</p><h3 id="general-design-of-deployment" tabindex="-1">General Design of Deployment <a class="header-anchor" href="#general-design-of-deployment" aria-label="Permalink to &quot;General Design of Deployment&quot;">​</a></h3><p>Brut attempts to consolidate all production deployment configuration in <code>deploy/deploy_config.rb</code>, which is expected to define the class <code>AppDeployConfig</code>, which is expected to extend <a href="/api/Brut/CLI/Apps/Deploy/DeployConfig.html" target="_self" rel="noopener" data-no-router><code>Brut::CLI::Apps::Deploy::DeployConfig</code></a>. Brut will create an instance of this class and use it to understand production aspects of your deployment. No YAML.</p><p>At its most basic, in production you will need to know what long-running processes to run. By default, you&#39;d run a web process, but you may also run Sidekiq or other services that need access to your app&#39;s source code.</p><p>The most full-featured method currently supported is Heroku, using containers.</p><h3 id="heroku-container-based-deployment" tabindex="-1">Heroku Container-based Deployment <a class="header-anchor" href="#heroku-container-based-deployment" aria-label="Permalink to &quot;Heroku Container-based Deployment&quot;">​</a></h3><p>When creating your Brut app with <code>brut new</code>, the Heroku segment can be used to create files for a <a href="https://devcenter.heroku.com/articles/container-registry-and-runtime" target="_blank" rel="noreferrer">Heroku container-based deployment</a>.</p><p>If you already created your app, you can add this segement via:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brut</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> segment</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> heroku</span></span></code></pre></div><p>How to deploy:</p><ol><li><p>Get an auth token from Heroku, which you can do from inside the container, and save it to <code>bash_customizations.local</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>your-computer&gt; dx/exec bash</span></span>
<span class="line"><span>devcontainer&gt; heroku auth:login</span></span>
<span class="line"><span># You will need to copy/paste the URL to log in</span></span>
<span class="line"><span>devcontainer&gt; heroku authorizations:create -d &quot;container pushes&quot; --expires-in 31536000</span></span>
<span class="line"><span># Copy the token output by this command</span></span>
<span class="line"><span>devcontainer&gt; echo &quot;HEROKU_API_KEY=«TOKEN YOU COPIED»&quot; &gt;&gt; dx/bash_customizations.local</span></span></code></pre></div></li><li><p>Exit the devcontainer and stop <code>dx/start</code> (e.g. hit <code>Ctrl-C</code> wherever you ran it)</p></li><li><p>Rebuild and restart the devcontainer (this will set <code>HEROKU_API_KEY</code> for you)</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>your-computer&gt; dx/build</span></span>
<span class="line"><span>your-computer&gt; dx/start</span></span>
<span class="line"><span># In another terminal window</span></span>
<span class="line"><span>your-computer&gt; dx/exec bash</span></span>
<span class="line"><span>devcontainer&gt; echo $HEROKU_API_KEY</span></span>
<span class="line"><span># You should see the token</span></span></code></pre></div><p>Setting this environment variable avoids having to constantly re-authenticate to Heroku.</p></li><li><p>Create your app using the container stack:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; heroku create --stack container -a «your heroku app name»</span></span></code></pre></div></li><li><p>Ensure your app&#39;s source code is all checked in, there are no uncommitted or unadded files, and you have pushed to the <code>main</code> branch of your remote Git repository.</p></li><li><p><code>brut deploy heroku</code></p><p>This will generate a <code>Dockerfile</code> for each process (by default, <code>Dockerfile.web</code> and <code>Dockerfile.release</code>), build images, push those images to Heroku, and ask Heroku to release them.</p></li></ol><p>Debugging Tips:</p><ul><li>Keep in mind it&#39;s hard to make general deployment tools. You are expected to understand your deployment and be capable of deploying an arbitrary Rack app manually. Brut&#39;s tooling automates what you need to do based on what you already need to know.</li><li>Try building images first: <code>brut deploy heroku --build-only</code></li><li>It&#39;s possible to run the images locally, but you will ned to run Postgres at the very least.</li></ul><h3 id="general-docker-image-deployment" tabindex="-1">General Docker Image Deployment <a class="header-anchor" href="#general-docker-image-deployment" aria-label="Permalink to &quot;General Docker Image Deployment&quot;">​</a></h3><p>When creating your Brut app with <code>brut new</code>, the DockerDeploy segment can be used to create files for a <a href="https://devcenter.heroku.com/articles/container-registry-and-runtime" target="_blank" rel="noreferrer">Heroku container-based deployment</a>.</p><p>If you already created your app, you can add this segement via:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brut</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> segment</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker-deploy</span></span></code></pre></div><p>This segment provides a more generic method of deployment using Docker images and Docker registries. Under this method, you author a <code>Dockerfile</code> which is then used to build an image whose name is based on your app&#39;s org and id (as defined in your subclass of <a href="/api/Brut/Framework/App.html" target="_self" rel="noopener" data-no-router><code>Brut::Framework::App</code></a>), as well as the current SHA-1 of your git repo. This image is then pushed to a registry of your choice. After that push, you are on your own to pull it down somewhere.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brut</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker</span></span></code></pre></div><p>You can do <code>brut deploy docker --no-push</code> to build only.</p><p>If you aren&#39;t using DockerHub, you can set your registry in <code>deploy/deploy_config.rb</code>:</p><div class="language-ruby vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ruby</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> AppDeployConfig</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Brut</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CLI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Apps</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Deploy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">DeployConfig</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> registry_hostname</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;ghcr.io&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">end</span></span></code></pre></div><h4 id="management-of-a-docker-compose-yml" tabindex="-1">Management of a <code>docker-compose.yml</code> <a class="header-anchor" href="#management-of-a-docker-compose-yml" aria-label="Permalink to &quot;Management of a \`docker-compose.yml\`&quot;">​</a></h4><p>If you want to use Docker Compose in production, Brut can assist with managing the <code>docker-compose.yml</code> file.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brut</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker_compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> generate</span></span></code></pre></div><p>This will create a <code>deploy/docker-compose.yml</code> if one is not there. It will have default settings that have worked for me, but you should review this file and make sure it&#39;s correct.</p><p>If the file <strong>is</strong> there, Brut will make it consistent with your <code>deploy/deploy_config.rb</code> file:</p><ul><li>Any service in <code>docker-compose.yml</code> that is not part of your config is removed</li><li>Any service <em>not</em> in <code>docker-compose.yml</code> will be added</li><li>Services in both <code>docker-compose.yml</code> and your config will be updated in <code>docker-compose.yml</code> as follows: <ul><li><code>command:</code> will be set to the command in your config</li><li><code>image:</code> will be set to <code>REGISTRY/ORG/APP_ID:\${DOCKER_IMAGE_TAG}</code>, where <code>REGISTRY</code> is the value from your deploy config and <code>ORG</code> and <code>APP_ID</code> are from your <code>App</code> class. Your production environment is expected to set <code>DOCKER_IMAGE_TAG</code> in the UNIX environment. This is because Brut&#39;s <code>brut deploy docker</code> implementation does not use <code>latest</code>, since <code>latest</code> in Docker-land is absolutely cursed.</li></ul></li></ul><p>Instead of changing the file, you can check its consistency first:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brut</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker_compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check</span></span></code></pre></div><p>This will output differences between what <code>generate</code> would do and what exists.</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Brut assumes your <code>deploy/docker-compose.yml</code> is to be checked in, so if you use <code>brut deploy docker_compose generate</code> to update it, you must commit and push that change to use <code>brut deploy docker</code>.</p></div><h3 id="other-mechanisms-for-deployment" tabindex="-1">Other Mechanisms for Deployment <a class="header-anchor" href="#other-mechanisms-for-deployment" aria-label="Permalink to &quot;Other Mechanisms for Deployment&quot;">​</a></h3><p>As a Rack app, other deployments should be possible. To make the app work, you&#39;ll need to make sure a few things are dealt with:</p><ul><li><code>RACK_ENV</code> <strong>must</strong> be <code>&quot;production&quot;</code></li><li><code>brut build-assets</code> will build all assets by default. This must either be done on production servers or done ahead of time and the results packaged with the app.</li><li><code>brut build-assets</code> outputs files in <code>app/public</code> and <code>app/config</code>. Those files are used at runtime. Brut <strong>will not</strong> initiate the build of any assets.</li><li>If you are going to build assets on production servers, you <em>must</em> included developer tooling. This means NodeJS, all modules in <code>package.json</code> and all RubyGems in <code>Gemfile</code>.</li></ul><h2 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h2><p>Testing deployments is a bit out of scope, but in general:</p><ul><li>A container-based deployment can theoretically be run on your computer as a test.</li><li>Non-production, but production-like environments can be used to validate production configurations.</li><li>You own the means of production…not Brut.</li></ul><h2 id="recommended-practices" tabindex="-1">Recommended Practices <a class="header-anchor" href="#recommended-practices" aria-label="Permalink to &quot;Recommended Practices&quot;">​</a></h2><ul><li>Avoid a lot of code that checks <code>Brut.container.project_env</code>. Try to consolidate all prod/test/dev differences in environment variables.</li><li>Have a way to get a shell into your production environment for debugging.</li><li>Brut doesn&#39;t log much, but if you remove the <code>OTEL_*</code> environment variables, Brut will log OTel telemetry to the console, which may be useful.</li><li>Setting <code>OTEL_LOG_LEVEL=debug</code> is advised if the app isn&#39;t starting or you aren&#39;t seeing any telemetry or logging</li></ul><h2 id="technical-notes" tabindex="-1">Technical Notes <a class="header-anchor" href="#technical-notes" aria-label="Permalink to &quot;Technical Notes&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Technical Notes are for deeper understanding and debugging. While we will try to keep them up-to-date with changes to Brut&#39;s internals, the source code is always more correct.</p></div><p><em>Last Updated July 3, 2025</em></p><p>None at this time.</p>`,48)])])}const k=a(i,[["render",n]]);export{u as __pageData,k as default};
